mapper.select:
select id, bank_name, category_name, question_count, difficulty, status, update_time, created_at, updated_at, created_by, updated_by, deleted from question_banks
and deleted = false
and (bank_name like concat('%', #{keyword}, '%') or category_name like concat('%', #{keyword}, '%'))
and status = #{status}
order by id desc limit #{pageSize} offset #{offset}

mapper.insert:
insert into question_banks (
  bank_name, category_name, question_count, difficulty, status, update_time,
  created_at, updated_at, created_by, updated_by, deleted
)
values (
  #{bankName}, #{categoryName}, #{questionCount}, #{difficulty}, #{status}, #{updateTime},
  #{createdAt}, #{updatedAt}, #{createdBy}, #{updatedBy}, #{deleted}
)

mapper.update:
update question_banks
set deleted = true,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where id = #{id}
  and deleted = false
